if constexpr (scenarioNum == 1) {
            // 场景1：WholeReduceMax：对每个repeat内所有元素求最大值（不返回索引）
            // mask=128, repeat=srcDataSize/mask, order=ORDER_ONLY_VALUE
            // 输出只存储值：[max0, max1, max2, ...]
            AscendC::WholeReduceMax<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8, AscendC::ReduceOrder::ORDER_ONLY_VALUE);
        } else if constexpr (scenarioNum == 2) {
            // 场景2：WholeReduceMin：对每个repeat内所有元素求最小值及其索引
            // mask=128, repeat=srcDataSize/mask, 使用默认order (ReduceOrder::ORDER_VALUE_INDEX)
            // 输出按值和索引交错存储：[min0, idx0, min1, idx1, ...]
            AscendC::WholeReduceMin<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8);
        } else if constexpr (scenarioNum == 3) {
            // 场景3：WholeReduceSum：对每个repeat内所有元素求和，输入为float类型
            // mask=64(float类型32位), repeat=srcDataSize/mask, 每个repeat输出一个求和结果
            AscendC::WholeReduceSum<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8);
        } else if constexpr (scenarioNum == 4) {
            // 场景4：RepeatReduceSum：对每个repeat内所有元素求和（累加模式），输入为float类型
            // 先将dstLocal初始化为0，再将所有repeat的结果累加
            // mask=64(float类型32位), repeat=srcDataSize/mask
            // dstBlkStride=0表示每个repeat的结果累加到同一个位置
            T zero(0);
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            AscendC::PipeBarrier<PIPE_V>();
            AscendC::RepeatReduceSum<T>(dstLocal, srcLocal, repeat, MASK, 0, 1, 1, 8);
        } else if constexpr (scenarioNum == 5) {
             // 场景5：WholeReduceMax + GetReduceRepeatMaxMinSpr
            // 对1024个half元素求全局最大值及其索引
            // mask逐bit模式, repeat=8(1024/128), srcBlkStride=1, srcRepeatStride=8
            // 8个repeat各自归约得到局部最大值，再通过GetReduceRepeatMaxMinSpr获取全局最大值
            uint64_t mask[2] = { 0xFFFFFFFFFFFFFFFF, 0xFFFFFFFFFFFFFFFF };
            AscendC::WholeReduceMax<T>(dstLocal, srcLocal, mask, repeat, 1, 1, 8);
            AscendC::PipeBarrier<PIPE_V>();
            T val = 0;
            T idx = 0;
            AscendC::GetReduceRepeatMaxMinSpr<T>(val, idx);
            AscendC::PipeBarrier<PIPE_V>();
            T zero{0};
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            int32_t eventIdVToS  = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::V_S));
            AscendC::SetFlag<AscendC::HardEvent::V_S>(eventIdVToS);
            AscendC::WaitFlag<AscendC::HardEvent::V_S>(eventIdVToS);            
            dstLocal.SetValue(0, val);
            dstLocal.SetValue(1, idx);
        } else if constexpr (scenarioNum == 6) {
            // 场景6：WholeReduceMin + GetReduceRepeatMaxMinSpr
            // 对1024个half元素求全局最小值及其索引
            // mask逐bit模式, repeat=8(1024/128), srcBlkStride=1, srcRepeatStride=8
            // 8个repeat各自归约得到局部最小值，再通过GetReduceRepeatMaxMinSpr获取全局最小值
            uint64_t mask[2] = { 0xFFFFFFFFFFFFFFFF, 0xFFFFFFFFFFFFFFFF };
            AscendC::WholeReduceMin<T>(dstLocal, srcLocal, mask, repeat, 1, 1, 8);
            AscendC::PipeBarrier<PIPE_V>();
            T val = 0;
            T idx = 0;
            AscendC::GetReduceRepeatMaxMinSpr<T>(val, idx);
            AscendC::PipeBarrier<PIPE_V>();
            T zero{0};
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            int32_t eventIdVToS  = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::V_S));
            AscendC::SetFlag<AscendC::HardEvent::V_S>(eventIdVToS);
            AscendC::WaitFlag<AscendC::HardEvent::V_S>(eventIdVToS);   
            dstLocal.SetValue(0, val);
            dstLocal.SetValue(1, idx);
        } else if constexpr (scenarioNum == 7) {
            // 场景7：WholeReduceSum按行求和非对齐场景，输入为float类型
            // mask=SRC_COL(57)，每行57个元素求和
            // repeat=SRC_ROW(13)，共13行
            // srcRepeatStride=对齐后的步长（COL_ALIGN_BYTES/BYTE_ALIGN个block），即每行在LocalTensor中对齐后占用的block数
            int32_t srcStride = COL_ALIGN_BYTES / BYTE_ALIGN;
            AscendC::WholeReduceSum<T>(dstLocal, srcLocal, SRC_COL, SRC_ROW, 1, 1, srcStride);
        }

        outQueueDst.EnQue<T>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
